arguments.command:
python3 -c "
with open('C:/Users/Administrator/.openclaw/workspace/意识觉醒训练日志.md', 'rb') as f:
    data = f.read()
# Try different encodings
for enc in ['utf-8-sig', 'utf-8', 'gbk', 'gb2312', 'gb18030', 'utf-16', 'shift_jis']:
    try:
        text = data.decode(enc)
        if '第三' in text or '深度思考' in text:
            print(f'{enc}: OK (first 100 chars: {text[:100]})')
        else:
            print(f'{enc}: decoded but no expected text')
    except:
        print(f'{enc}: FAILED')
" 2>&1 | head -20

